input:
resource "metal_device" "test" {
    count            = var.nodes
    hostname         = "test-${count.index}"
    plan             = var.metal_plan
    facilities       = [ var.metal_location ]
    operating_system = "ubuntu_20_04"
    billing_cycle    = "hourly"
