    type = "ssh"
    user = "ubuntu"
    private_key = "${tls_private_key.ssh-key.private_key_pem}"
    host = "${google_compute_instance.openstack.network_interface.0.access_config.0.nat_ip}"
  }
  provisioner "remote-exec" {
    script = "script.sh"
  }
}

